import static org.junit.jupiter.api.Assertions.*;

public class PasswordGeneratorTest {

    @Test
    public void testGeneratePasswordValidLength() {
        String password = PasswordGenerator.generatePassword(12);
        assertNotNull(password);
        assertEquals(12, password.length());
    }

    @Test
    public void testGeneratePasswordZeroLength() {
        String password = PasswordGenerator.generatePassword(0);
        assertEquals("", password);
    }

    @Test
    public void testGeneratePasswordNegativeLength() {
        Exception exception = assertThrows(IllegalArgumentException.class, () -> {
            PasswordGenerator.generatePassword(-5);
        });
        assertEquals("Password length must be positive.", exception.getMessage());
    }

    @Test
    public void testGeneratePasswordWithMinimumLength() {
        String password = PasswordGenerator.generatePassword(1);
        assertNotNull(password);
        assertEquals(1, password.length());
    }

    @Test
    public void testGeneratePasswordWithMixedCharacters() {
        String password = PasswordGenerator.generatePassword(12);
        assertTrue(password.chars().anyMatch(Character::isUpperCase));
        assertTrue(password.chars().anyMatch(Character::isLowerCase));
        assertTrue(password.chars().anyMatch(Character::isDigit));
        assertTrue(password.chars().anyMatch(ch -> "!@#$%^&*()".indexOf(ch) >= 0));
    }

    @Test
    public void testGeneratePasswordLargeLength() {
        String password = PasswordGenerator.generatePassword(100);
        assertNotNull(password);
        assertEquals(100, password.length());
    }

    @Test
    public void testMainMethodOutput() {
        // This test can be more complex by capturing the output stream if needed.
        // For simplicity, we will just call the method and not assert anything.
        PasswordGenerator.main(new String[]{});
    }
}
